package main

import (
    "fmt"
    "strconv"
    "strings"
)

func main() {
    // ---- strings package ----
    fmt.Println("=== strings package ===")

    s := "Hello, World!"

    // ---- Basic string operations ----
    fmt.Println("Contains:", strings.Contains(s, "World"))
    fmt.Println("Contains:", strings.Contains(s, "Go"))
    fmt.Println("Count:", strings.Count(s, "l"))
    fmt.Println("HasPrefix:", strings.HasPrefix(s, "Hello"))
    fmt.Println("HasSuffix:", strings.HasSuffix(s, "!"))
    fmt.Println("Index:", strings.Index(s, "World"))
    fmt.Println("LastIndex:", strings.LastIndex(s, "l"))

    // ---- Case conversion ----
    fmt.Println("ToUpper:", strings.ToUpper(s))
    fmt.Println("ToLower:", strings.ToLower(s))
    fmt.Println("Title:", strings.Title(s))

    // ---- Trimming ----
    trimmed := "  Hello, World!  "
    fmt.Println("TrimSpace:", strings.TrimSpace(trimmed))
    fmt.Println("Trim:", strings.Trim(trimmed, " !"))

    // ---- Splitting and joining ----
    words := strings.Split(s, ", ")
    fmt.Println("Split:", words)

    joined := strings.Join(words, " - ")
    fmt.Println("Join:", joined)

    // ---- Replacing ----
    replaced := strings.ReplaceAll(s, "World", "Go")
    fmt.Println("Replace:", replaced)

    // ---- strconv package ----
    fmt.Println("\n=== strconv package ===")

    // ---- String to int ----
    numStr := "42"
    num, err := strconv.Atoi(numStr)
    if err == nil {
        fmt.Printf("Atoi: %d\n", num)
    }

    // ---- Int to string ----
    intVal := 123
    strVal := strconv.Itoa(intVal)
    fmt.Println("Itoa:", strVal)

    // ---- String to float ----
    floatStr := "3.14"
    floatVal, err := strconv.ParseFloat(floatStr, 64)
    if err == nil {
        fmt.Printf("ParseFloat: %.2f\n", floatVal)
    }

    // ---- Float to string ----
    f := 3.14159
    fs := strconv.FormatFloat(f, 'f', 2, 64)
    fmt.Println("FormatFloat:", fs)

    // ---- String to bool ----
    boolVal, err := strconv.ParseBool("true")
    if err == nil {
        fmt.Println("ParseBool:", boolVal)
    }

    // ---- String to int with base ----
    hexVal, err := strconv.ParseInt("FF", 16, 64)
    if err == nil {
        fmt.Printf("ParseInt hex: %d\n", hexVal)
    }

    // ---- Int to string with base ----
    binStr := strconv.FormatInt(255, 2)
    fmt.Println("FormatInt binary:", binStr)
}

